interface File {
  type: "file";
  name: string;
  size: number; // size in bytes
}

interface Folder {
  type: "folder";
  name: string;
  children: FileSystemItem[]; // recursive reference here
}

type FileSystemItem = File | Folder;

const myFileSystem: FileSystemItem = {
  type: "folder",
  name: "root",
  children: [
    {
      type: "file",
      name: "photo.png",
      size: 3400
    },
    {
      type: "folder",
      name: "documents",
      children: [
        {
          type: "file",
          name: "resume.pdf",
          size: 12000
        }
      ]
    }
  ]
};

function getTotalSize(item: FileSystemItem): number {
  if (item.type === "file") {
    return item.size;
  } else {
    return item.children.reduce((total, child) => total + getTotalSize(child), 0);
  }
}

console.log(`Total size: ${getTotalSize(myFileSystem)} bytes`);

class ApiError extends Error {
  statusCode: number;
  constructor(message: string, statusCode: number) {
    super(message);
    this.name = 'ApiError';
    this.statusCode = statusCode;
  }
}

class NetworkError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'NetworkError';
  }
}

async function fetchUserData(userId: string) {
  try {
    const response = await fetch(`https://api.example.com/users/${userId}`);
    if (!response.ok) {
      throw new ApiError('Failed to fetch user data', response.status);
    }
    return await response.json();
  } catch (error) {
    if (error instanceof ApiError) {
      // Handle known API errors
      console.error('API error:', error.message);
    } else {
      // Handle network errors or unknown issues
      console.error('Unexpected error:', error);
    }
    return null; // Return null or a fallback to keep the system stable
  }
}

async function retry<T>(fn: () => Promise<T>, retries = 3, delay = 500): Promise<T> {
  try {
    return await fn();
  } catch (error) {
    if (retries === 0) throw error;
    await new Promise(resolve => setTimeout(resolve, delay));
    return retry(fn, retries - 1, delay * 2);
  }
}

// Usage example:
async function getUser() {
  return retry(() => fetchUserData('123'));
}

function timeout<T>(promise: Promise<T>, ms: number): Promise<T> {
  return new Promise((resolve, reject) => {
    const timer = setTimeout(() => {
      reject(new NetworkError('Request timed out'));
    }, ms);
    promise
      .then(value => {
        clearTimeout(timer);
        resolve(value);
      })
      .catch(err => {
        clearTimeout(timer);
        reject(err);
      });
  });
}

// Usage example:
async function fetchWithTimeout() {
  try {
    const data = await timeout(fetchUserData('123'), 3000); // 3 seconds timeout
    return data;
  } catch (error) {
    console.error(error);
    return null;
  }
}

